import{_ as s,c as a,a as e,o as t}from"./app-BdEkBqzb.js";const p={};function o(i,n){return t(),a("div",null,n[0]||(n[0]=[e(`<h1 id="国际化多语言方案" tabindex="-1"><a class="header-anchor" href="#国际化多语言方案"><span>国际化多语言方案</span></a></h1><p>生产环境的国际化方案采用的是社区提供的方法：<a href="https://vip.kingdee.com/school/detail/238388113520005120?productLineId=29&amp;lang=zh-CN" target="_blank" rel="noopener noreferrer">自定义控件的多语言开发</a></p><p>主要利用的 API 为 <code>window.KDApi.getLangMsg</code></p><p>开发环境没有这个 API，我做了一层封装来模拟行为，保证开发环境和生产环境的代码编写是一样的，效果也是一样的，直接使用即可。</p><p>同时，无论选择 React 还是 Vue，写法都一样。</p><p>使用例子：</p><div class="language-jsx line-numbers-mode" data-highlighter="prismjs" data-ext="jsx"><pre><code><span class="line"><span class="token keyword">import</span> getLangMsg <span class="token keyword">from</span> <span class="token string">&quot;@utils/langMsg&quot;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 例子获取一个词条</span></span>
<span class="line"><span class="token keyword">function</span> <span class="token function">getMsg</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> msg <span class="token operator">=</span> <span class="token function">getLangMsg</span><span class="token punctuation">(</span><span class="token string">&quot;name&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>国际化文本维护在 <code>src/lang</code> 文件夹中。正常情况下至少要在本地提供一个中文词条和英文字条的 JSON 文件。一般发布的时候，会有对应的流水根据中文词条去把其他语言的词条生成出来。</p><p>如果不需要国际化，那就不使用这个 API，并且在 <code>index.ts</code> 中注册控件时取消多语言配置 <code>{ isMulLang: true }</code></p>`,9)]))}const l=s(p,[["render",o]]),r=JSON.parse('{"path":"/internationalization/introduce.html","title":"国际化多语言方案","lang":"zh-CN","frontmatter":{},"headers":[],"git":{},"filePathRelative":"internationalization/introduce.md"}');export{l as comp,r as data};
